# Practical: safe input conversion
def safe_int(text):
    try:
        return int(text)
    except ValueError:
        return None

print(safe_int("42"))    # 42
print(safe_int("hello")) # None

exercises.solution:
def safe_divide(a, b):
    try:
        return a / b
    except ZeroDivisionError:
        print("Cannot divide by zero")
        return None

print(safe_divide(10, 2))
print(safe_divide(5, 0))

def get_item(my_list, index):
    try:
        return my_list[index]
    except IndexError:
        print("Index out of range")
        return None

print(get_item([1, 2, 3], 1))
print(get_item([1, 2, 3], 10))

def parse_age(text):
    try:
        return int(text)
    except ValueError:
        print("Please enter a valid number")
        return None

result1 = parse_age("25")
print(result1)

result2 = parse_age("old")
print(result2)
